{"type": "post", "post": {"team": "payment_operations", "channel": "vendor_payments", "user": "mary_li", "message": "I've updated the vendor list with the new additions. Please check it and let me know if there are any discrepancies.", "created_at": 1620500010000}}
{"type": "post", "post": {"team": "it_security", "channel": "cybersecurity", "user": "david_chen", "message": "We've just completed an upgrade to our firewalls. This should improve our overall network security.", "created_at": 1620500020000}}
{"type": "post", "post": {"team": "payment_operations", "channel": "vendor_payments", "user": "jason.wong", "message": "I'll be working with the IT team this week on a security review for our payment systems. Let's schedule a meeting to discuss our findings next week.", "created_at": 1620500030000}}
