{"type": "post", "post": {"team": "it_security", "channel": "cybersecurity", "user": "david_chen", "message": "Just a quick update - we're rolling out a new security training module next week. Please make sure your teams complete it by end of the month.", "created_at": 1620500050000}}
{"type": "post", "post": {"team": "payment_operations", "channel": "vendor_payments", "user": "jason.wong", "message": "We've received a few inquiries about our vendor payment timelines. Let's discuss how we can streamline the process in our next team meeting.", "created_at": 1620500060000}}
{"type": "post", "post": {"team": "it_security", "channel": "cybersecurity", "user": "jason.wong", "message": "Our phishing simulation tests are showing improvement, good job team. Let's keep up the good work!", "created_at": 1620500070000}}
{"type": "post", "post": {"team": "payment_operations", "channel": "vendor_payments", "user": "mary_li", "message": "Just want to give a shout-out to Jason for his great work this month. He's been key in helping us automate our vendor payment process.", "create_at": 1620500000000}}
{"type": "post", "post": {"team": "payment_operations", "channel": "vendor_payments", "user": "jason.wong", "message": "Thanks, Mary. I'm glad I could help. We've been able to implement batch processing scripts for vendor payments which has significantly reduced the manual entries needed.", "create_at": 1620500000500}}
{"type": "post", "post": {"team": "payment_operations", "channel": "vendor_payments", "user": "mary_li", "message": "That's an understatement, Jason! We've cut manual entries by around 70% thanks to your work. This automation is a game-changer for us.", "create_at": 1620500001000}}
